package com.example.madodict

import android.content.Context
import android.content.res.Configuration
import androidx.annotation.StringRes
import java.util.Locale

enum class AppLanguage(val locale: Locale) {
    ZH(Locale.SIMPLIFIED_CHINESE),
    EN(Locale.ENGLISH)
}

fun appString(
    context: Context,
    language: AppLanguage,
    @StringRes resId: Int,
    vararg formatArgs: Any
): String {
    val config = Configuration(context.resources.configuration).apply {
        setLocale(language.locale)
    }
    val localizedContext = context.createConfigurationContext(config)
    return localizedContext.resources.getString(resId, *formatArgs)
}

package com.example.madodict

import android.content.Context
import android.content.res.Configuration
import android.os.Build
import android.os.LocaleList
import androidx.annotation.StringRes
import java.util.Locale

enum class AppLanguage(val locale: Locale) {
    ZH(Locale.SIMPLIFIED_CHINESE),
    EN(Locale.ENGLISH)
}

fun appString(
    context: Context,
    language: AppLanguage,
    @StringRes resId: Int,
    vararg formatArgs: Any
): String {
    val baseConfig = context.resources.configuration
    val config = Configuration(baseConfig)
    val locale = language.locale
    if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.N) {
        config.setLocales(LocaleList(locale))
    } else {
        @Suppress("DEPRECATION")
        config.setLocale(locale)
    }
    config.setLayoutDirection(locale)
    val localizedContext = context.createConfigurationContext(config)
    return localizedContext.resources.getString(resId, *formatArgs)
}

package com.example.madodict

import android.content.Context
import androidx.datastore.preferences.core.Preferences
import androidx.datastore.preferences.core.booleanPreferencesKey
import androidx.datastore.preferences.core.edit
import androidx.datastore.preferences.core.stringPreferencesKey
import androidx.datastore.preferences.preferencesDataStore
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.map

private val Context.dataStore by preferencesDataStore(name = "app_preferences")

class AppPreferences(private val context: Context) {
    private object Keys {
        val DarkTheme = booleanPreferencesKey("pref_dark_theme")
        val Language = stringPreferencesKey("pref_language")
    }

    val darkThemeFlow: Flow<Boolean> = context.dataStore.data.map { prefs ->
        prefs[Keys.DarkTheme] ?: false
    }

    val languageFlow: Flow<AppLanguage> = context.dataStore.data.map { prefs ->
        val stored = prefs[Keys.Language]
        AppLanguage.values().firstOrNull { it.name == stored } ?: AppLanguage.ZH
    }

    suspend fun setDarkTheme(enabled: Boolean) {
        context.dataStore.edit { prefs: Preferences ->
            prefs[Keys.DarkTheme] = enabled
        }
    }

    suspend fun setLanguage(language: AppLanguage) {
        context.dataStore.edit { prefs: Preferences ->
            prefs[Keys.Language] = language.name
        }
    }
}

