private val Context.dataStore by preferencesDataStore(name = "app_preferences")

class AppPreferences(private val context: Context) {
    private object Keys {
        val DarkTheme = booleanPreferencesKey("pref_dark_theme")
        val Language = stringPreferencesKey("pref_language")
    }

    val darkThemeFlow: Flow<Boolean?> = context.dataStore.data.map { prefs ->
        prefs[Keys.DarkTheme]
    }

    val languageFlow: Flow<AppLanguage> = context.dataStore.data.map { prefs ->
        val stored = prefs[Keys.Language]
        AppLanguage.values().firstOrNull { it.name == stored } ?: AppLanguage.ZH
    }

    suspend fun setDarkTheme(enabled: Boolean) {
        context.dataStore.edit { prefs: Preferences ->
            prefs[Keys.DarkTheme] = enabled
        }
    }

    suspend fun setLanguage(language: AppLanguage) {
        context.dataStore.edit { prefs: Preferences ->
            prefs[Keys.Language] = language.name
        }
    }
}

package com.example.madodict
import androidx.compose.runtime.Composable import androidx.compose.runtime.getValue import androidx.compose.runtime.mutableStateOf import androidx.compose.runtime.saveable.rememberSaveable import androidx.compose.runtime.setValue
@Composable fun AppRoot( language: AppLanguage, isDarkTheme: Boolean, onThemeChange: (Boolean) -> Unit, onLanguageChange: (AppLanguage) -> Unit ) { var selectedTab by rememberSaveable { mutableStateOf(0) }
when (selectedTab) { 0 -> DictionaryScreen( runeEntries = defaultRuneEntries, selectedTab = 0, onTabSelected = { selectedTab = it }, language = language ) 1 -> ConverterScreen( selectedTab = 1, onTabSelected = { selectedTab = it }, language = language ) 2 -> SettingsScreen( selectedTab = 2, onTabSelected = { selectedTab = it }, switchSelected = isDarkTheme, onThemeChange = onThemeChange, language = language, onLanguageChange = onLanguageChange ) } }

package com.example.madodict

import androidx.compose.runtime.Composable
import androidx.compose.runtime.getValue
import androidx.compose.runtime.mutableStateOf
import androidx.compose.runtime.saveable.rememberSaveable
import androidx.compose.runtime.setValue
import androidx.compose.runtime.LaunchedEffect
import kotlinx.coroutines.delay

@Composable
fun AppRoot(
    language: AppLanguage,
    isDarkTheme: Boolean,
    onThemeChange: (Boolean) -> Unit,
    onLanguageChange: (AppLanguage) -> Unit
) {
    var selectedTab by rememberSaveable { mutableStateOf(0) }
    var showBootScreen by rememberSaveable { mutableStateOf(true) }

    LaunchedEffect(Unit) {
        delay(1200L)
        showBootScreen = false
        selectedTab = 0
    }

    if (showBootScreen) {
        BootScreen()
        return
    }

    when (selectedTab) {
        0 -> DictionaryScreen(
            runeEntries = defaultRuneEntries,
            selectedTab = 0,
            onTabSelected = { selectedTab = it },
            language = language
        )
        1 -> ConverterScreen(
            selectedTab = 1,
            onTabSelected = { selectedTab = it },
            language = language
        )
        2 -> SettingsScreen(
            selectedTab = 2,
            onTabSelected = { selectedTab = it },
            switchSelected = isDarkTheme,
            onThemeChange = onThemeChange,
            language = language,
            onLanguageChange = onLanguageChange
        )
    }
}

