                }

                Button(
                    onClick = {
                        if (previewText.isNotEmpty()) {
                            exportAsSvg(context, previewText, selectedSize, textColor)
                        } else {
                            Toast.makeText(
                                context,
                                appString(context, language, R.string.converter_export_empty_hint),
                                Toast.LENGTH_SHORT
                            ).show()
